package main

import (
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// RequestBody defines the structure for the incoming JSON payload
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var body RequestBody
	if err := ctx.BodyParser(&body); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	// Validate that the URL is not empty
	if body.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout as requested
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the provided webhook URL
	resp, err := client.Get(body.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook endpoint returned a non-success status code
	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": fmt.Sprintf("Webhook URL validation failed with status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration logic would go here.
	// For this snippet, we will assume it is saved successfully.

	// Return a success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured and validated successfully",
		"url":     body.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
