package main

import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookConfig stores the configured webhook URL in memory.
// In a production application, this would typically be stored in a database.
var (
	webhookConfig struct {
		sync.RWMutex
		url string
	}
)

// WebhookRequest defines the expected JSON payload structure.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to configure and validate a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON format",
		})
	}

	// Basic validation to ensure the field is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "field 'webhook_url' is required",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the webhook URL to validate it
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"status":  "failed",
			"message": "Failed to validate webhook URL",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the remote server returned a non-success status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "failed",
			"message": "Webhook URL returned an error status",
			"code":    resp.StatusCode,
		})
	}

	// Save the configuration (thread-safe)
	webhookConfig.Lock()
	webhookConfig.url = req.WebhookURL
	webhookConfig.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Register the route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server started on :3000")
	log.Fatal(app.Listen(":3000"))
}

