// RequestPayload defines the expected JSON structure
type RequestPayload struct {
	WebhookURL string `json:"webhook_url"`
}

// Global variable to simulate saving the configuration
var savedWebhookURL string

// ConfigureWebhook handles the POST request to configure and validate a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the JSON body
	var payload RequestPayload
	if err := ctx.BodyParser(&payload); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid JSON payload",
			"error":   err.Error(),
		})
	}

	// Basic validation to ensure the field is not empty
	if payload.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url field is required",
		})
	}

	// 2. Validate the webhook URL by sending a GET request
	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(payload.WebhookURL)
	if err != nil {
		// If the request fails (e.g., timeout, DNS error, connection refused)
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL. The URL might be unreachable.",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the remote server returned a success status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL validation failed",
			"details": "Remote server returned status: " + resp.Status,
		})
	}

	// 3. Save the configuration
	savedWebhookURL = payload.WebhookURL
	log.Printf("Webhook configured successfully: %s", savedWebhookURL)

	// 4. Return a JSON response with the result
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured and validated successfully",
		"data": fiber.Map{
			"webhook_url": savedWebhookURL,
		},
	})
}

func main() {
	app := fiber.New()

	// Define the route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server started on :3000")
	log.Fatal(app.Listen(":3000"))
}

