)

// In-memory storage to simulate saving the configuration
var savedWebhookURL string

// WebhookRequest defines the expected JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the JSON body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON format",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url field is required",
		})
	}

	// 2. Validate the webhook URL by sending a test GET request with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
