package main

import (
	"context"
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// RequestPayload defines the expected JSON structure
type RequestPayload struct {
	WebhookURL string `json:"webhook_url"`
}

// ResponsePayload defines the JSON response structure
type ResponsePayload struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// Global variable to simulate saving the configuration
var configuredWebhookURL string

// ConfigureWebhook handles the POST request to set up a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the JSON body
	var payload RequestPayload
	if err := ctx.BodyParser(&payload); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponsePayload{
			Success: false,
			Message: "Invalid request body",
		})
	}

	// 2. Validate that webhook_url is provided
	if payload.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponsePayload{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// 3. Validate the webhook URL by sending a GET request
	// Create a context with timeout to ensure the request doesn't hang indefinitely
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create the HTTP request
	req, err := http.NewRequestWithContext(reqCtx, http.MethodGet, payload.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(ResponsePayload{
			Success: false,
			Message: "Failed to create validation request",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Execute the request
	resp, err := client.Do(req)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponsePayload{
			Success: false,
			Message: "Webhook validation failed: URL is unreachable or timed out",
		})
	}
	defer resp.Body.Close()

	// Check if the webhook returned a successful status code (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponsePayload{
			Success: false,
			Message: "Webhook validation failed: URL returned non-success status",
		})
	}

	// 4. Save the configuration
	configuredWebhookURL = payload.WebhookURL
	log.Printf("Webhook configured successfully: %s", configuredWebhookURL)

	// 5. Return success response
	return ctx.Status(fiber.StatusOK).JSON(ResponsePayload{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

