// ConfigureWebhook handles the POST request to configure and validate a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid JSON format",
		})
	}

	// Validate the webhook URL by sending a test GET request
	// Requirement: Set timeout to 3 seconds
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook validation failed",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook endpoint is reachable and returns a valid status
	if resp.StatusCode != http.StatusOK {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned non-200 status",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration (Simulated persistence)
	// In a real-world scenario, this would be saved to a database or config file
	log.Printf("Configuration saved: WebhookURL=%s", config.WebhookURL)

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured and validated successfully",
		"data": fiber.Map{
			"webhook_url": config.WebhookURL,
		},
	})
}

