package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variable to simulate saving the configuration
var savedWebhookURL string

// WebhookRequest defines the expected JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to configure and validate a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the JSON body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "error",
			"message": "Cannot parse JSON",
			"error":   err.Error(),
		})
	}

	// 2. Validate the webhook URL by sending a test request
	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "validation_failed",
			"message": "Failed to reach webhook URL",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the endpoint returns a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"status":  "validation_failed",
			"message": "Webhook URL returned non-success status",
			"code":    resp.StatusCode,
		})
	}

	// 3. Save the configuration
	savedWebhookURL = req.WebhookURL

	// 4. Return a JSON response with the result
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured successfully",
		"url":     savedWebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/configure", ConfigureWebhook)

	log.Fatal(app.Listen(":3000"))
}

