// WebhookRequest defines the structure of the incoming JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse defines the structure of the response
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the configuration of the webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a GET request to validate the URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status code indicates success
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save the configuration (In-memory storage for demonstration purposes)
	// In a production environment, this would be persisted to a database.
	log.Printf("Webhook configured successfully: %s", req.WebhookURL)

	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Println("Server is running on port 3000")
	log.Fatal(app.Listen(":3000"))
}

