package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the JSON structure for the incoming request
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the configuration of a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Invalid JSON format",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a GET request to validate the URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":   "Failed to validate webhook URL",
			"details": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook URL returned a non-success status code
	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error":       "Webhook URL validation failed",
			"status_code": resp.StatusCode,
		})
	}

	// Save the configuration (In a real application, this would be saved to a database)
	// For this example, we assume it is saved successfully.

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured successfully",
		"url":     req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Println("Server starting on port 3000...")
	log.Fatal(app.Listen(":3000"))
}

