package main

import (
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the expected JSON payload
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse defines the JSON response structure
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// In-memory storage to simulate saving the configuration
var savedWebhookURL string

// ConfigureWebhook handles the POST request to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// 1. Parse the JSON body
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url field is required",
		})
	}

	// 2. Validate the webhook URL by sending a GET request with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook endpoint returns a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// 3. Save the configuration (simulated in-memory)
	savedWebhookURL = req.WebhookURL
	fmt.Printf("Configuration updated. Webhook URL: %s\n", savedWebhookURL)

	// 4. Return a JSON response with the result
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	fmt.Println("Server is running on :3000")
	app.Listen(":3000")
}

