package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variable to simulate saving the configuration
var savedWebhookURL string

// ConfigureWebhook handles the POST request to configure a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define the request structure
	type Request struct {
		WebhookURL string `json:"webhook_url"`
	}

	var req Request

	// Parse the JSON body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Cannot parse JSON",
		})
	}

	// Validate that the URL is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusServiceUnavailable).JSON(fiber.Map{
			"error": "Failed to validate webhook URL",
			"detail": err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the status code indicates success
	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"error": "Webhook URL returned an error status",
			"status_code": resp.StatusCode,
		})
	}

	// Save the configuration
	savedWebhookURL = req.WebhookURL
	log.Printf("Webhook configured: %s", savedWebhookURL)

	// Return a success response
	return ctx.JSON(fiber.Map{
		"status":  "success",
		"message": "Webhook configured and validated",
		"url":     savedWebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	log.Println("Server running on http://localhost:3000")
	log.Fatal(app.Listen(":3000"))
}

