package main

import (
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the expected JSON payload structure.
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Response defines the structure of the JSON response returned to the client.
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the POST request to configure and validate a webhook URL.
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body from the request
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON body provided",
		})
	}

	// Validate that the webhook_url field is not empty
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Field 'webhook_url' is required",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send a test GET request to the provided webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Failed to validate webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook endpoint returned a non-success status code
	if resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook URL validation failed with status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration.
	// Note: Since no database is specified, we simulate saving by logging.
	// In a production environment, this would involve saving to a DB or config store.
	fmt.Printf("Webhook configuration saved successfully for URL: %s\n", req.WebhookURL)

	// Return a success response
	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/configure", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

