package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookRequest defines the expected JSON payload structure
type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse defines the structure of the JSON response
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// Global variable to simulate persistent storage of the configuration
var configuredWebhookURL string

// ConfigureWebhook handles the POST request to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body from the request
	var req WebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body provided",
		})
	}

	// Validate the webhook URL by sending a test GET request
	// Requirement: Timeout must be set to 3 seconds
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Ensure the webhook URL responds with a 200 OK status
	if resp.StatusCode != http.StatusOK {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Webhook URL returned non-200 status code",
		})
	}

	// Save the configuration
	configuredWebhookURL = req.WebhookURL
	log.Printf("Webhook configured successfully: %s", configuredWebhookURL)

	// Return a success response
	return ctx.JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured and validated successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the route
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	log.Println("Server is running on port 3000")
	log.Fatal(app.Listen(":3000"))
}

