package main

import (
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// RequestBody defines the structure of the incoming JSON request
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// Global variable to store the configuration in memory
var savedWebhookURL string

// ConfigureWebhook handles the POST request to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON body
	var body RequestBody
	if err := ctx.BodyParser(&body); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid JSON payload",
		})
	}

	// Ensure the URL is not empty
	if body.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Validate the webhook URL by sending a GET request
	resp, err := client.Get(body.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the endpoint returned a non-success status code
	if resp.StatusCode >= http.StatusBadRequest {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned an error",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration
	savedWebhookURL = body.WebhookURL
	log.Printf("Webhook configured: %s", savedWebhookURL)

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"url":     savedWebhookURL,
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server
	log.Println("Server started on :3000")
	log.Fatal(app.Listen(":3000"))
}

